class CheckoutService {
  applyDiscount(customer: Customer, total: number): number {
    if (customer.getTier() === 'gold' && customer.getPurchaseCount() > 10) {
      return total * 0.85;
    }
    if (customer.getTier() === 'silver') {
      return total * 0.95;
    }
    return total;
  }
}

class AccessService {
  canDownload(user: User, doc: Document): boolean {
    const active = user.getStatus() === 'active';
    const paid = user.getPlan() !== 'free';
    const owner = user.getId() === doc.getOwnerId();
    const internal = doc.getVisibility() === 'internal';
    return active && paid && (owner || internal);
  }
}

