class BillingService {
  renew(account: Account): void {
    if (account.getStatus() === 'past_due' && account.getRetries() < 3) {
      account.chargeAgain();
    }
  }
}
// Version B
class Account {
  renew(): void {
    if (this.status === 'past_due' && this.retries < 3) this.chargeAgain();
  }
}
